// bashCompletionScript is the static bash completion script for vprox.
// Generated by `vprox completion bash`.
const bashCompletionScript = `# vprox bash completion script
# Generated by: vprox completion bash
#
# To enable in the current shell session:
#   source <(vprox completion bash)
#
# To install permanently:
#   vprox completion --install-bash
#   # Then add to ~/.bashrc: source ~/.bash_completion.d/vprox

_vprox_completions() {
    local cur prev words cword
    _init_completion 2>/dev/null || {
        COMPREPLY=()
        cur="${COMP_WORDS[COMP_CWORD]}"
        prev="${COMP_WORDS[COMP_CWORD-1]}"
        words=("${COMP_WORDS[@]}")
        cword=$COMP_CWORD
    }

    local commands="start stop restart status fleet mod chain config completion vops"
    local global_flags="--help --version --home --config --validate --info --dry-run --quiet --verbose --daemon --debug --with-vops -d"

    if [[ $cword -eq 1 ]]; then
        COMPREPLY=($(compgen -W "${commands} ${global_flags}" -- "$cur"))
        return 0
    fi

    local subcmd="${words[1]}"
    case "$subcmd" in
        config)
            COMPREPLY=($(compgen -W "ports settings chain vlog fleet infra backup list validate" -- "$cur"))
            ;;
        fleet)
            COMPREPLY=($(compgen -W "list status push sync chains unregister" -- "$cur"))
            ;;
        completion)
            COMPREPLY=($(compgen -W "bash zsh fish --install-bash --install-zsh" -- "$cur"))
            ;;
        vops)
            COMPREPLY=($(compgen -W "start stop status version archives accounts threats enrich cache ingest" -- "$cur"))
            ;;
        start|stop|restart|status)
            COMPREPLY=($(compgen -W "${global_flags}" -- "$cur"))
            ;;
        *)
            COMPREPLY=($(compgen -W "${global_flags}" -- "$cur"))
            ;;
    esac

    return 0
}

complete -F _vprox_completions vprox
`

// zshCompletionScript is the static zsh completion script for vprox.
// Generated by `vprox completion zsh`.
const zshCompletionScript = `#compdef vprox
# vprox zsh completion script
# Generated by: vprox completion zsh
#
# To enable in the current shell session:
#   source <(vprox completion zsh)
#
# To install permanently:
#   vprox completion --install-zsh

_vprox() {
    local -a commands
    commands=(
        'start:start the vProx proxy server (foreground, journald-friendly)'
        'stop:stop the vProx.service daemon'
        'restart:restart the vProx.service daemon'
        'status:show service status'
        'fleet:manage remote VMs and deployments'
        'mod:manage vProx ecosystem modules'
        'chain:chain node status and upgrade tracking'
        'config:interactive TOML configuration wizard'
        'completion:generate shell completion scripts'
        'vops:vOps dashboard and analytics (integrated vLog)'
    )

    local -a global_flags
    global_flags=(
        '--help:show help and exit'
        '--version:show version and exit'
        '--home:override VPROX_HOME directory'
        '--config:override config directory'
        '--validate:validate configs and exit'
        '--info:show loaded config summary and exit'
        '--dry-run:load everything but do not start server'
        '--quiet:suppress non-error output'
        '--verbose:verbose logging output'
        '--daemon:start as background daemon via sudo service'
        '--debug:enable debug mode'
        '--with-vops:start with vOps/dashboard module'
        '-d:alias for --daemon'
    )

    _arguments -C \
        '1: :->command' \
        '*:: :->args'

    case $state in
        command)
            _describe 'vprox command' commands
            _describe 'global flag' global_flags
            ;;
        args)
            case $words[1] in
                config)
                    _values 'config subcommand' \
                        'ports[configure port assignments]' \
                        'settings[general proxy settings]' \
                        'chain[chain proxy config]' \
                        'vlog[vLog/vOps config]' \
                        'fleet[fleet SSH settings]' \
                        'infra[infra datacenter registry]' \
                        'backup[backup automation settings]' \
                        'list[list all loaded configs]' \
                        'validate[validate all config files]'
                    ;;
                fleet)
                    _values 'fleet subcommand' \
                        'list[list registered VMs]' \
                        'status[show fleet status]' \
                        'push[push scripts to fleet]' \
                        'sync[sync fleet state]' \
                        'chains[list registered chains]' \
                        'unregister[unregister a chain from SQLite]'
                    ;;
                completion)
                    _values 'shell' 'bash' 'zsh' 'fish'
                    _arguments \
                        '--install-bash[install bash completion to ~/.bash_completion.d/vprox]' \
                        '--install-zsh[install zsh completion]'
                    ;;
                vops)
                    _values 'vops subcommand' \
                        'start[start vOps standalone]' \
                        'stop[stop vOps]' \
                        'status[show vOps status]' \
                        'version[show vOps version]' \
                        'archives[list log archives]' \
                        'accounts[manage IP accounts]' \
                        'threats[view threat intelligence]' \
                        'enrich[enrich IP addresses]' \
                        'cache[cache management]' \
                        'ingest[ingest log archives]'
                    ;;
                *)
                    _describe 'global flag' global_flags
                    ;;
            esac
            ;;
    esac
}

_vprox "$@"
`

