// generateBashCompletion returns the static bash completion script for vprox.
func generateBashCompletion() string {
	return bashCompletionScript
}

// generateZshCompletion returns the static zsh _vprox completion function for vprox.
func generateZshCompletion() string {
	return zshCompletionScript
}

// generateFishCompletion returns the static fish completion script for vprox.
func generateFishCompletion() string {
	return fishCompletionScript
}

// installCompletion writes the completion script for the specified shell to its
// conventional per-user completion directory and prints setup instructions.
//
// Supported shells: bash, zsh.
func installCompletion(shell, script string) error {
	homeDir, err := os.UserHomeDir()
	if err != nil {
		return fmt.Errorf("installCompletion: get home dir: %w", err)
	}

	var dest, instructions string

	switch shell {
	case "bash":
		dir := filepath.Join(homeDir, ".bash_completion.d")
		if err := os.MkdirAll(dir, 0755); err != nil {
			return fmt.Errorf("installCompletion: mkdir %s: %w", dir, err)
		}
		dest = filepath.Join(dir, "vprox")
		instructions = fmt.Sprintf(
			"Add the following line to ~/.bashrc to load completions:\n"+
				"  source %s\n\n"+
				"Or reload in the current session:\n"+
				"  source <(vprox completion bash)",
			dest,
		)

	case "zsh":
		// Probe in order: oh-my-zsh, ~/.zsh/completions, ~/.zshrc.d
		dir := ""
		candidates := []string{
			filepath.Join(homeDir, ".oh-my-zsh", "completions"),
			filepath.Join(homeDir, ".zsh", "completions"),
			filepath.Join(homeDir, ".zshrc.d"),
		}
		for _, c := range candidates {
			if _, statErr := os.Stat(c); statErr == nil {
				dir = c
				break
			}
		}
		if dir == "" {
			// Create ~/.zsh/completions as fallback
			dir = filepath.Join(homeDir, ".zsh", "completions")
			if err := os.MkdirAll(dir, 0755); err != nil {
				return fmt.Errorf("installCompletion: mkdir %s: %w", dir, err)
			}
		}
		dest = filepath.Join(dir, "_vprox")
		instructions = fmt.Sprintf(
			"Ensure %s is in $fpath. Add to ~/.zshrc if needed:\n"+
				"  fpath=(%s $fpath)\n"+
				"  autoload -U compinit && compinit",
			dir, dir,
		)

	default:
		return fmt.Errorf("unsupported shell %q for --install (supported: bash, zsh)", shell)
	}

	if err := os.WriteFile(dest, []byte(script), 0644); err != nil {
		return fmt.Errorf("installCompletion: write %s: %w", dest, err)
	}

	fmt.Printf("✓ Installed %s completion → %s\n\n", shell, dest)
	fmt.Println(instructions)
	return nil
}

// runCompletionCmd handles the `vprox completion` command.
//
// Usage:
//
//	vprox completion bash            — print bash completion script to stdout
//	vprox completion zsh             — print zsh completion script to stdout
//	vprox completion fish            — print fish completion script to stdout
//	vprox completion --install-bash  — install bash completion file
//	vprox completion --install-zsh   — install zsh completion file
func runCompletionCmd(args []string) {
	if len(args) == 0 {
		fmt.Fprintln(os.Stderr, "Usage: vprox completion [bash|zsh|fish]")
		fmt.Fprintln(os.Stderr, "       vprox completion --install-bash")
		fmt.Fprintln(os.Stderr, "       vprox completion --install-zsh")
		os.Exit(1)
	}

	// Scan for install flags (may appear before or instead of shell name)
	for _, a := range args {
		switch a {
		case "--install-bash":
			if err := installCompletion("bash", generateBashCompletion()); err != nil {
				fmt.Fprintf(os.Stderr, "vprox: %v\n", err)
				os.Exit(1)
			}
			return
		case "--install-zsh":
			if err := installCompletion("zsh", generateZshCompletion()); err != nil {
				fmt.Fprintf(os.Stderr, "vprox: %v\n", err)
				os.Exit(1)
			}
			return
		}
	}

	shell := strings.ToLower(args[0])
	switch shell {
	case "bash":
		fmt.Print(generateBashCompletion())
	case "zsh":
		fmt.Print(generateZshCompletion())
	case "fish":
		fmt.Print(generateFishCompletion())
	default:
		fmt.Fprintf(os.Stderr, "vprox completion: unknown shell %q\n", shell)
		fmt.Fprintln(os.Stderr, "Supported shells: bash, zsh, fish")
		os.Exit(1)
	}
}
